func editorTitle(invoice *mock.Invoice) string {
	if invoice != nil {
		return "Edit " + invoice.Number
	}
	return "New Invoice"
}

func getInitialLineItems(invoice *mock.Invoice) string {
	if invoice != nil && len(invoice.LineItems) > 0 {
		return `[
			{id: 1, description: "` + invoice.LineItems[0].Description + `", quantity: ` + formatFloat(invoice.LineItems[0].Quantity) + `, rate: ` + formatFloat(invoice.LineItems[0].Rate) + `}
		]`
	}
	return `[{id: 1, description: '', quantity: 1, rate: 0}]`
}

func formatFloat(f float64) string {
	return fmt.Sprintf("%.2f", f)
}

func getInvoiceNotes(invoice *mock.Invoice) string {
	if invoice != nil {
		return invoice.Notes
	}
	return ""
}

